def enable_windows_dpi_awareness() -> None:
    try:
        import ctypes

        user32 = ctypes.windll.user32
        try:
            user32.SetProcessDpiAwarenessContext(ctypes.c_void_p(-4))
            return
        except (AttributeError, OSError):
            pass
        try:
            ctypes.windll.shcore.SetProcessDpiAwareness(2)
            return
        except (AttributeError, OSError):
            pass
        try:
            user32.SetProcessDPIAware()
        except (AttributeError, OSError):
            pass
    except Exception:
        pass


enable_windows_dpi_awareness()


def apply_windows_dark_titlebar(window: tk.Misc) -> None:
    if sys.platform != "win32":
        return

    def apply_once() -> None:
        try:
            if not window.winfo_exists():
                return
            window.update_idletasks()
            import ctypes

            value = ctypes.c_int(1)
            user32 = ctypes.windll.user32
            dwmapi = ctypes.windll.dwmapi
            hwnd = int(window.winfo_id())
            handles = [hwnd]
            parent_hwnd = int(user32.GetParent(hwnd))
            if parent_hwnd and parent_hwnd not in handles:
                handles.append(parent_hwnd)
            for target_hwnd in handles:
                for attribute in (20, 19):
                    try:
                        result = dwmapi.DwmSetWindowAttribute(
                            target_hwnd,
                            attribute,
                            ctypes.byref(value),
                            ctypes.sizeof(value),
                        )
                        if result == 0:
                            break
                    except (AttributeError, OSError):
                        continue
        except Exception:
            pass

    try:
        window.after(0, apply_once)
        window.after(160, apply_once)
    except tk.TclError:
        apply_once()


