def normalized_telemetry_game_value(value) -> str:
    text = str(value or "").strip().lower().replace(" ", "_").replace("-", "_")
    if text in {"motorsport", "forza_motorsport", "fm", "fm2023"}:
        return TELEMETRY_GAME_MOTORSPORT
    return TELEMETRY_GAME_HORIZON


