def running_frozen() -> bool:
    return bool(getattr(sys, "frozen", False))


def executable_dir() -> Path:
    if running_frozen():
        return Path(sys.executable).resolve().parent
    return Path(__file__).resolve().parent


def app_work_dir() -> Path:
    try:
        return Path.cwd().resolve()
    except OSError:
        return executable_dir()


def user_data_dir() -> Path:
    if running_frozen():
        local_app_data = os.environ.get("LOCALAPPDATA")
        if local_app_data:
            return Path(local_app_data) / "DualSense Haptic Translator"
    return Path(__file__).resolve().parent


def package_root_candidates() -> list[Path]:
    candidates = []
    if running_frozen() and hasattr(sys, "_MEIPASS"):
        candidates.append(Path(getattr(sys, "_MEIPASS")))
    candidates.extend([
        app_work_dir(),
        executable_dir(),
        executable_dir().parent,
        Path(__file__).resolve().parent,
        Path(__file__).resolve().parent.parent,
    ])
    unique: list[Path] = []
    seen: set[str] = set()
    for candidate in candidates:
        try:
            resolved = candidate.resolve()
        except OSError:
            resolved = candidate
        key = str(resolved).lower()
        if key in seen:
            continue
        seen.add(key)
        unique.append(resolved)
    return unique


def packaged_file_candidates(*parts: str) -> list[Path]:
    return [root.joinpath(*parts) for root in package_root_candidates()]


def first_existing_packaged_file(*parts: str) -> Path | None:
    for candidate in packaged_file_candidates(*parts):
        if candidate.exists():
            return candidate
    return None


