def parse_packet_horizon_324(packet: bytes) -> dict[str, float | int | bool]:
    """Parse the protected Forza Horizon 324-byte Data Out packet."""
    if len(packet) != FORZA_HORIZON_PACKET_SIZE:
        raise ValueError(f"expected Horizon {FORZA_HORIZON_PACKET_SIZE} bytes, got {len(packet)}")

    parsed = parse_packet_common_prefix(packet, puddle_reader=_int)
    parsed.update({
        "telemetry_game": TELEMETRY_GAME_HORIZON,
        "telemetry_format": "horizon_324",
        "car_group": _uint(packet, 232),
        "smashable_vel_diff": _float(packet, 236),
        "smashable_mass": _float(packet, 240),
        "position_x": _float(packet, 244),
        "position_y": _float(packet, 248),
        "position_z": _float(packet, 252),
        "speed_kmh": _float(packet, 256) * 3.6,
        "power": _float(packet, 260),
        "torque": _float(packet, 264),
        "tire_temp_fl": _float(packet, 268),
        "tire_temp_fr": _float(packet, 272),
        "tire_temp_rl": _float(packet, 276),
        "tire_temp_rr": _float(packet, 280),
        "boost": _float(packet, 284),
        "fuel": _float(packet, 288),
        "distance_traveled": _float(packet, 292),
        "best_lap_time": _float(packet, 296),
        "last_lap_time": _float(packet, 300),
        "current_lap_time": _float(packet, 304),
        "current_race_time": _float(packet, 308),
        "lap_number": _short(packet, 312),
        "race_position": packet[314],
        "accel": packet[315],
        "brake": packet[316],
        "clutch": packet[317],
        "handbrake": packet[318],
        "gear": packet[319],
        "steer": _sbyte(packet, 320),
        "normalized_driving_line": _sbyte(packet, 321),
        "normalized_ai_brake_difference": _sbyte(packet, 322),
        "tire_wear_fl": 0.0,
        "tire_wear_fr": 0.0,
        "tire_wear_rl": 0.0,
        "tire_wear_rr": 0.0,
        "track_ordinal": 0,
    })
    return parsed


def parse_packet_motorsport_dash_332(packet: bytes) -> dict[str, float | int | bool]:
    """Parse Forza Motorsport Dash packets while preserving internal field names."""
    packet_len = len(packet)
    if packet_len not in {FORZA_MOTORSPORT_DASH_PACKET_SIZE, FORZA_MOTORSPORT_DASH_PADDED_PACKET_SIZE}:
        raise ValueError(
            f"expected Motorsport Dash {FORZA_MOTORSPORT_DASH_PACKET_SIZE} bytes, got {packet_len}"
        )
    tire_wear_offset = 311 if packet_len == FORZA_MOTORSPORT_DASH_PACKET_SIZE else 312

    parsed = parse_packet_common_prefix(packet, puddle_reader=_float)
    parsed.update({
        "telemetry_game": TELEMETRY_GAME_MOTORSPORT,
        "telemetry_format": f"motorsport_dash_{packet_len}",
        "car_group": 0,
        "smashable_vel_diff": 0.0,
        "smashable_mass": 0.0,
        "position_x": _float(packet, 232),
        "position_y": _float(packet, 236),
        "position_z": _float(packet, 240),
        "speed_kmh": _float(packet, 244) * 3.6,
        "power": _float(packet, 248),
        "torque": _float(packet, 252),
        "tire_temp_fl": _float(packet, 256),
        "tire_temp_fr": _float(packet, 260),
        "tire_temp_rl": _float(packet, 264),
        "tire_temp_rr": _float(packet, 268),
        "boost": _float(packet, 272),
        "fuel": _float(packet, 276),
        "distance_traveled": _float(packet, 280),
        "best_lap_time": _float(packet, 284),
        "last_lap_time": _float(packet, 288),
        "current_lap_time": _float(packet, 292),
        "current_race_time": _float(packet, 296),
        "lap_number": _short(packet, 300),
        "race_position": packet[302],
        "accel": packet[303],
        "brake": packet[304],
        "clutch": packet[305],
        "handbrake": packet[306],
        "gear": packet[307],
        "steer": _sbyte(packet, 308),
        "normalized_driving_line": _sbyte(packet, 309),
        "normalized_ai_brake_difference": _sbyte(packet, 310),
        "tire_wear_fl": _float(packet, tire_wear_offset),
        "tire_wear_fr": _float(packet, tire_wear_offset + 4),
        "tire_wear_rl": _float(packet, tire_wear_offset + 8),
        "tire_wear_rr": _float(packet, tire_wear_offset + 12),
        "track_ordinal": _int(packet, tire_wear_offset + 16),
    })
    return parsed


def parse_packet(packet: bytes, telemetry_game: str = TELEMETRY_GAME_HORIZON) -> dict[str, float | int | bool]:
    game = normalized_telemetry_game_value(telemetry_game)
    packet_len = len(packet)
    if game == TELEMETRY_GAME_MOTORSPORT:
        if packet_len in {FORZA_MOTORSPORT_DASH_PACKET_SIZE, FORZA_MOTORSPORT_DASH_PADDED_PACKET_SIZE}:
            return parse_packet_motorsport_dash_332(packet)
        if packet_len == FORZA_MOTORSPORT_SLED_PACKET_SIZE:
            raise ValueError(
                "Forza Motorsport Sled packet detected. Set Data Out Packet Format to Dash."
            )
        if packet_len == FORZA_HORIZON_PACKET_SIZE:
            raise ValueError(
                "Horizon-size packet received while Motorsport is selected. Select Horizon for this packet."
            )
        raise ValueError(
            f"expected Motorsport Dash {FORZA_MOTORSPORT_DASH_PACKET_SIZE} bytes, got {packet_len}"
        )

    if packet_len == FORZA_HORIZON_PACKET_SIZE:
        return parse_packet_horizon_324(packet)
    if packet_len in {FORZA_MOTORSPORT_DASH_PACKET_SIZE, FORZA_MOTORSPORT_DASH_PADDED_PACKET_SIZE}:
        raise ValueError(
            "Forza Motorsport Dash packet detected while Horizon is selected. Use SELECT GAME > Motorsport."
        )
    if packet_len == FORZA_MOTORSPORT_SLED_PACKET_SIZE:
        raise ValueError(
            "Forza Motorsport Sled packet detected. Select Motorsport and set Data Out Packet Format to Dash."
        )
    raise ValueError(f"expected Horizon {FORZA_HORIZON_PACKET_SIZE} bytes, got {packet_len}")


def max_abs(t: dict[str, float | int | bool], prefix: str) -> float:
    return max(abs(float(t[f"{prefix}_{wheel}"])) for wheel in ("fl", "fr", "rl", "rr"))


def derived_signals(t: dict[str, float | int | bool]) -> dict[str, float]:
    max_rpm = max(float(t["max_rpm"]), 1.0)
    accel_g = math.sqrt(
        float(t["accel_x"]) ** 2 + float(t["accel_y"]) ** 2 + float(t["accel_z"]) ** 2
    )
    return {
        "rpm_ratio": max(0.0, min(1.3, float(t["rpm"]) / max_rpm)),
        "speed_kmh": max(0.0, float(t["speed_kmh"])),
        "accel": float(t["accel"]),
        "brake": float(t["brake"]),
        "gear": float(t["gear"]),
        "slip_ratio_max": max_abs(t, "tire_slip_ratio"),
        "slip_combined_max": max_abs(t, "tire_combined_slip"),
        "surface_rumble_max": max_abs(t, "surface_rumble"),
        "smashable_vel_diff": max(0.0, float(t["smashable_vel_diff"])),
        "accel_g": accel_g,
    }


def parse_packet_field_names() -> list[str]:
    sample = bytes(PACKET_SIZE)
    return list(parse_packet(sample).keys())


def derived_field_names() -> list[str]:
    sample = parse_packet(bytes(PACKET_SIZE))
    return list(derived_signals(sample).keys())


