def alias_key(value: str) -> str:
    return "".join(ch for ch in value.lower() if ch.isalnum())


def build_alias_map() -> dict[str, str]:
    aliases: dict[str, str] = {}
    for official, internal in OFFICIAL_FIELD_ALIASES.items():
        aliases[alias_key(official)] = internal
        aliases[alias_key(internal)] = internal
    for name in FIELD_DEFAULT_SCALES:
        aliases[alias_key(name)] = name
    return aliases


FIELD_ALIASES = build_alias_map()


class UDPWorker(threading.Thread):
    def __init__(
        self,
        host: str,
        port: int,
        out_queue: queue.Queue,
        relay_enabled: bool = False,
        relay_host: str = DEFAULT_TELEMETRY_RELAY_HOST,
        relay_port: int = DEFAULT_TELEMETRY_RELAY_PORT,
        telemetry_game: str = TELEMETRY_GAME_HORIZON,
    ):
        super().__init__(daemon=True)
        self.host = host
        self.port = port
        self.out_queue = out_queue
        self.stop_event = threading.Event()
        self.relay_lock = threading.Lock()
        self.telemetry_game_lock = threading.Lock()
        self.telemetry_game = normalized_telemetry_game_value(telemetry_game)
        self.relay_enabled = bool(relay_enabled)
        self.relay_host = relay_host.strip() or DEFAULT_TELEMETRY_RELAY_HOST
        self.relay_port = int(relay_port)
        self.relay_sock: socket.socket | None = None
        self.relay_error_at = 0.0

    def update_relay(self, enabled: bool, host: str, port: int) -> None:
        with self.relay_lock:
            self.relay_enabled = bool(enabled)
            self.relay_host = host.strip() or DEFAULT_TELEMETRY_RELAY_HOST
            self.relay_port = int(port)

    def relay_target(self) -> tuple[bool, str, int]:
        with self.relay_lock:
            return self.relay_enabled, self.relay_host, self.relay_port

    def update_telemetry_game(self, telemetry_game: str) -> None:
        with self.telemetry_game_lock:
            self.telemetry_game = normalized_telemetry_game_value(telemetry_game)

    def telemetry_game_value(self) -> str:
        with self.telemetry_game_lock:
            return self.telemetry_game

    def close_relay_socket(self) -> None:
        sock = self.relay_sock
        self.relay_sock = None
        if sock is not None:
            try:
                sock.close()
            except OSError:
                pass

    def forward_packet(self, packet: bytes) -> None:
        enabled, host, port = self.relay_target()
        if not enabled:
            return
        try:
            if self.relay_sock is None:
                self.relay_sock = socket.socket(socket.AF_INET, socket.SOCK_DGRAM)
            self.relay_sock.sendto(packet, (host, port))
        except OSError as exc:
            self.close_relay_socket()
            now = time.monotonic()
            if now - self.relay_error_at >= TELEMETRY_RELAY_ERROR_INTERVAL_S:
                self.relay_error_at = now
                self.out_queue.put(("telemetry_relay_error", now, f"{host}:{port}", str(exc)))

    def run(self) -> None:
        sock = socket.socket(socket.AF_INET, socket.SOCK_DGRAM)
        sock.setsockopt(socket.SOL_SOCKET, socket.SO_RCVBUF, 4096)
        try:
            sock.bind((self.host, self.port))
        except OSError as exc:
            self.out_queue.put(("bind_error", time.monotonic(), f"{self.host}:{self.port}", str(exc)))
            sock.close()
            return
        sock.settimeout(0.5)

        while not self.stop_event.is_set():
            try:
                packet, addr = sock.recvfrom(1500)
            except socket.timeout:
                continue

            sock.setblocking(False)
            try:
                while True:
                    packet, addr = sock.recvfrom(1500)
            except (BlockingIOError, OSError):
                pass
            finally:
                sock.setblocking(True)
                sock.settimeout(0.5)

            try:
                parsed = parse_packet(packet, self.telemetry_game_value())
            except ValueError as exc:
                self.out_queue.put(("bad_packet", time.monotonic(), str(exc)))
                continue

            self.forward_packet(packet)
            self.out_queue.put(("packet", time.monotonic(), addr, parsed, derived_signals(parsed)))

        sock.close()
        self.close_relay_socket()


class TriggerStatusWorker(threading.Thread):
    def __init__(self, port: int, out_queue: queue.Queue):
        super().__init__(daemon=True)
        self.port = port
        self.out_queue = out_queue
        self.stop_event = threading.Event()

    def run(self) -> None:
        sock = socket.socket(socket.AF_INET, socket.SOCK_DGRAM)
        try:
            sock.bind(("127.0.0.1", self.port))
        except OSError as exc:
            self.out_queue.put(("trigger_status_error", time.monotonic(), str(exc)))
            sock.close()
            return
        sock.settimeout(0.5)

        while not self.stop_event.is_set():
            try:
                packet, _addr = sock.recvfrom(512)
            except socket.timeout:
                continue
            try:
                message = packet.decode("ascii", errors="ignore").strip()
            except UnicodeDecodeError:
                continue
            values: dict[str, float | str] = {}
            parts = message.split("|")
            if not parts or parts[0] != "DUALSENSE_INPUT":
                continue
            for part in parts[1:]:
                key, sep, value = part.partition("=")
                if not sep:
                    continue
                try:
                    values[key] = float(value)
                except ValueError:
                    values[key] = value
            if values:
                self.out_queue.put(("trigger_status", time.monotonic(), values))

        sock.close()


class BubbleTooltip:
    """Canvas-drawn dark tooltip box."""

    VALID_TAILS = {"top-left", "top-right", "bottom-left", "bottom-right"}

    def __init__(
        self,
        root: tk.Tk,
        widget: tk.Widget,
        title: str,
        body: str = "",
        *,
        placement: str = "below",
        tail: str = "top-left",
        delay_ms: int = 550,
        max_width: int = 300,
        enabled_callback=None,
    ):
        self.root = root
        self.widget = widget
        self.title = title
        self.body = body
        self.placement = placement
        self.tail = tail if tail in self.VALID_TAILS else "top-left"
        self._placement_to_use = self.placement
        self._tail_to_draw = self.tail
        self.delay_ms = delay_ms
        self.max_width = max_width
        self.enabled_callback = enabled_callback
        self.after_id: str | None = None
        self.popup: tk.Toplevel | None = None
        self._close_after_id: str | None = None

        widget.bind("<Enter>", self.schedule, add="+")
        widget.bind("<Leave>", self.hide, add="+")
        widget.bind("<ButtonPress>", self.hide, add="+")
        widget.bind("<Destroy>", self.hide, add="+")

    def enabled(self) -> bool:
        if self.enabled_callback is None:
            return True
        try:
            return bool(self.enabled_callback())
        except Exception:
            return False

    def schedule(self, _event=None) -> None:
        self.cancel_schedule()
        if not self.enabled():
            return
        self.after_id = self.widget.after(self.delay_ms, self.show)

    def cancel_schedule(self) -> None:
        if self.after_id is None:
            return
        try:
            self.widget.after_cancel(self.after_id)
        except tk.TclError:
            pass
        self.after_id = None

    def hide(self, _event=None) -> None:
        self.cancel_schedule()
        self.cancel_close_schedule()
        if self.popup is not None:
            try:
                self.popup.destroy()
            except tk.TclError:
                pass
            self.popup = None

    def schedule_close(self, _event=None) -> None:
        self.cancel_close_schedule()
        if self.popup is not None:
            self._close_after_id = self.popup.after(160, self.hide)

    def cancel_close_schedule(self, _event=None) -> None:
        if self._close_after_id is None or self.popup is None:
            self._close_after_id = None
            return
        try:
            self.popup.after_cancel(self._close_after_id)
        except tk.TclError:
            pass
        self._close_after_id = None

    def show(self) -> None:
        self.after_id = None
        if not self.enabled():
            return
        try:
            if not self.widget.winfo_exists():
                return
        except tk.TclError:
            return
        self.hide()

        self.resolve_auto_geometry()
        self.root.update_idletasks()
        popup = tk.Toplevel(self.root)
        popup.overrideredirect(True)
        popup.attributes("-topmost", True)
        popup.configure(bg="#101316")
        try:
            popup.wm_attributes("-transparentcolor", "#101316")
        except tk.TclError:
            pass

        canvas, width, height = self.build_canvas(popup)
        canvas.pack(fill="both", expand=True)
        x, y = self.position(width, height)
        popup.geometry(f"{width}x{height}+{x}+{y}")
        popup.bind("<Enter>", self.cancel_close_schedule, add="+")
        popup.bind("<Leave>", self.schedule_close, add="+")
        self.popup = popup

    def resolve_auto_geometry(self) -> None:
        self._placement_to_use = self.placement
        self._tail_to_draw = self.tail
        if self.placement != "auto":
            return
        try:
            wy = self.widget.winfo_rooty()
            wh = max(1, self.widget.winfo_height())
        except tk.TclError:
            return
        approximate_height = 156
        _left, _top, _right, bottom = self.root_area()
        below = wy + wh + approximate_height + 8 <= bottom
        side = "left" if self.tail.endswith("left") else "right"
        self._placement_to_use = "below" if below else "above"
        self._tail_to_draw = f"top-{side}" if below else f"bottom-{side}"

    def tooltip_fonts(self) -> tuple[tkfont.Font, tkfont.Font]:
        return (
            tkfont.Font(root=self.root, font=ui_font("Segoe UI", 11, "bold")),
            tkfont.Font(root=self.root, font=ui_font("Segoe UI", 10)),
        )

    def text_lines(
        self,
        max_text_width: int,
        title_font: tkfont.Font,
        body_font: tkfont.Font,
    ) -> tuple[list[str], list[str]]:
        title_lines = self.wrap_text_pixels(self.title.upper(), title_font, max_text_width)
        body_lines = self.wrap_text_pixels(self.body, body_font, max_text_width) if self.body else []
        return title_lines, body_lines

    def wrap_text_pixels(self, text: str, font: tkfont.Font, max_width: int) -> list[str]:
        max_width = max(40, int(max_width))
        lines: list[str] = []
        for paragraph in str(text).splitlines() or [""]:
            words = paragraph.split()
            if not words:
                lines.append("")
                continue
            current = ""
            for word in words:
                candidate = word if not current else f"{current} {word}"
                if font.measure(candidate) <= max_width:
                    current = candidate
                    continue
                if current:
                    lines.append(current)
                if font.measure(word) <= max_width:
                    current = word
                else:
                    split_lines = self.split_long_word_pixels(word, font, max_width)
                    lines.extend(split_lines[:-1])
                    current = split_lines[-1] if split_lines else ""
            if current:
                lines.append(current)
        return lines

    def split_long_word_pixels(self, word: str, font: tkfont.Font, max_width: int) -> list[str]:
        parts: list[str] = []
        current = ""
        for char in str(word):
            candidate = current + char
            if current and font.measure(candidate) > max_width:
                parts.append(current)
                current = char
            else:
                current = candidate
        if current:
            parts.append(current)
        return parts or [str(word)]

    def build_canvas(self, popup: tk.Toplevel) -> tuple[tk.Canvas, int, int]:
        pad_x = 22
        pad_y = 17
        area_left, _area_top, area_right, _area_bottom = self.root_area()
        available_width = max(180, area_right - area_left - 8)
        max_width = max(180, min(self.max_width, available_width))
        max_text_width = max(40, max_width - pad_x * 2)
        title_font, body_font = self.tooltip_fonts()
        title_lines, body_lines = self.text_lines(max_text_width, title_font, body_font)
        title_h = max(20, title_font.metrics("linespace") + 4)
        body_h = max(18, body_font.metrics("linespace") + 4)
        gap = 8 if title_lines and body_lines else 0
        measured_text_width = max(
            [title_font.measure(line) for line in title_lines]
            + [body_font.measure(line) for line in body_lines]
            + [120]
        )
        min_width = min(max_width, 180)
        width = min(max_width, max(min_width, measured_text_width + pad_x * 2))
        bubble_h = pad_y * 2 + len(title_lines) * title_h + gap + len(body_lines) * body_h
        height = bubble_h + 8
        canvas = tk.Canvas(popup, width=width, height=height, bg="#101316", highlightthickness=0, bd=0)

        bubble_top = 1
        bubble_bottom = bubble_top + bubble_h
        bubble_left = 1
        bubble_right = width - 1
        radius = 9
        fill = "#171b20"
        outline = "#f1c40f"
        shadow = "#050607"

        self.draw_round_rect(canvas, bubble_left + 2, bubble_top + 2, bubble_right, bubble_bottom, radius, fill=shadow, outline="")
        self.draw_round_rect(canvas, bubble_left, bubble_top, bubble_right - 2, bubble_bottom - 2, radius, fill=fill, outline=outline)

        text_x = pad_x
        text_y = bubble_top + pad_y
        for line in title_lines:
            canvas.create_text(
                text_x,
                text_y,
                anchor="nw",
                text=line,
                fill="#f1c40f",
                font=title_font,
            )
            text_y += title_h
        if body_lines:
            text_y += gap
        for line in body_lines:
            canvas.create_text(
                text_x,
                text_y,
                anchor="nw",
                text=line,
                fill="#d6dde5",
                font=body_font,
            )
            text_y += body_h
        return canvas, width, height

    def draw_round_rect(self, canvas: tk.Canvas, x1: int, y1: int, x2: int, y2: int, radius: int, **kwargs) -> None:
        points = [
            x1 + radius, y1,
            x2 - radius, y1,
            x2, y1,
            x2, y1 + radius,
            x2, y2 - radius,
            x2, y2,
            x2 - radius, y2,
            x1 + radius, y2,
            x1, y2,
            x1, y2 - radius,
            x1, y1 + radius,
            x1, y1,
        ]
        canvas.create_polygon(points, smooth=True, splinesteps=12, **kwargs)

    def position(self, width: int, height: int) -> tuple[int, int]:
        try:
            wx = self.widget.winfo_rootx()
            wy = self.widget.winfo_rooty()
            ww = max(1, self.widget.winfo_width())
            wh = max(1, self.widget.winfo_height())
        except tk.TclError:
            return 0, 0

        left, top, right, bottom = self.root_area()
        tooltip_gap = 34
        below = self._placement_to_use != "above"
        space_below = bottom - (wy + wh) - tooltip_gap
        space_above = wy - top - tooltip_gap
        if below and height > space_below and space_above > space_below:
            below = False
        elif not below and height > space_above and space_below > space_above:
            below = True
        x = wx if self._tail_to_draw.endswith("left") else wx + ww - width
        y = wy + wh + tooltip_gap if below else wy - height - tooltip_gap
        min_x = left + 4
        min_y = top + 4
        max_x = max(min_x, right - width - 4)
        max_y = max(min_y, bottom - height - 4)
        x = max(min_x, min(x, max_x))
        y = max(min_y, min(y, max_y))
        return int(x), int(y)

    def root_area(self) -> tuple[int, int, int, int]:
        try:
            self.root.update_idletasks()
            root_left = self.root.winfo_rootx()
            root_top = self.root.winfo_rooty()
            root_right = root_left + max(1, self.root.winfo_width())
            root_bottom = root_top + max(1, self.root.winfo_height())
        except tk.TclError:
            return self.work_area_for_widget()
        work_left, work_top, work_right, work_bottom = self.work_area_for_widget()
        left = max(work_left, root_left)
        top = max(work_top, root_top)
        right = min(work_right, root_right)
        bottom = min(work_bottom, root_bottom)
        if right - left < 120 or bottom - top < 80:
            return root_left, root_top, root_right, root_bottom
        return left, top, right, bottom

    def work_area_for_widget(self) -> tuple[int, int, int, int]:
        try:
            wx = self.widget.winfo_rootx()
            wy = self.widget.winfo_rooty()
            ww = max(1, self.widget.winfo_width())
            wh = max(1, self.widget.winfo_height())
            center_x = wx + ww / 2.0
            center_y = wy + wh / 2.0
        except tk.TclError:
            center_x = 0.0
            center_y = 0.0
        areas = windows_monitor_work_areas()
        if areas:
            for area in areas:
                left, top, right, bottom = area
                if left <= center_x < right and top <= center_y < bottom:
                    return area

            def distance(area: tuple[int, int, int, int]) -> float:
                left, top, right, bottom = area
                area_x = (left + right) / 2.0
                area_y = (top + bottom) / 2.0
                return (area_x - center_x) ** 2 + (area_y - center_y) ** 2

            return min(areas, key=distance)
        return (0, 0, self.root.winfo_screenwidth(), self.root.winfo_screenheight())


