        self.settings["gforce_hud_active"] = self.hud_window_exists(self.gforce_hud_window)
        self.settings["tire_hud_active"] = self.hud_window_exists(self.tire_hud_window)
        self.settings["steer_hud_active"] = self.hud_window_exists(self.steer_hud_window)
        self.settings["haptic_visual_hud_active"] = self.hud_window_exists(self.haptic_visual_hud_window)
        self.settings["haptic_debug_hud_active"] = self.hud_window_exists(self.haptic_debug_hud_window)
        self.settings["applied_steer_hud_active"] = False
        self.settings["rpm_hud_active"] = self.hud_window_exists(self.rpm_hud_window)
        self.settings["engine_hud_active"] = self.hud_window_exists(self.engine_hud_window)
        self.settings["trigger_hud_active"] = self.hud_window_exists(self.trigger_hud_window)
        self.settings["preset_hud_active"] = self.hud_window_exists(self.preset_hud_window)
        self.settings["trigger_debug_hud_active"] = self.hud_window_exists(self.trigger_debug_hud_window)
