    def decay_haptic_visual_bins(self) -> None:
        now = time.monotonic()
        dt = max(0.0, min(0.25, now - self.haptic_visual_last_decay_at))
        self.haptic_visual_last_decay_at = now
        if dt <= 0.0:
            return
        decay = max(0.0, 1.0 - dt * 4.8)
        self.haptic_visual_left_bins = [value * decay if value > 0.004 else 0.0 for value in self.haptic_visual_left_bins]
        self.haptic_visual_right_bins = [value * decay if value > 0.004 else 0.0 for value in self.haptic_visual_right_bins]

    def draw_haptic_visual_hud(self) -> None:
        canvas = self.haptic_visual_hud_canvas
        if canvas is None or self.haptic_visual_hud_window is None or not self.haptic_visual_hud_window.winfo_exists():
            return
        self.decay_haptic_visual_bins()
        width = max(48, canvas.winfo_width())
        height = max(120, canvas.winfo_height())
        canvas.delete("all")
        x0 = 0
        y0 = 0
        x1 = width
        y1 = height
        bg = "#151a20"
        line = "#252c35"
        center_line = "#3a4652"
        left_color = "#2f5e73"
        right_color = "#f1c40f"
        canvas.create_rectangle(x0, y0, x1, y1, fill=bg, outline="")
        right = x1 - 1
        bottom = y1 - 1
        canvas.create_line(x0, y0, right, y0, right, bottom, x0, bottom, x0, y0, fill=line, width=1)

        center_x = int(round(width * 0.5))
        left_zero_x = center_x - 4
        right_zero_x = center_x + 4
        canvas.create_line(center_x, y0 + 1, center_x, bottom - 1, fill=center_line, width=1)
        canvas.create_line(left_zero_x, y0 + 1, left_zero_x, bottom - 1, fill=line, width=1)
        canvas.create_line(right_zero_x, y0 + 1, right_zero_x, bottom - 1, fill=line, width=1)

        label_y = height * 0.10
        label_font = hud_font("Segoe UI", max(6, int(height * 0.055)), "bold")
        label_color = "#3a4652"
        canvas.create_text(left_zero_x * 0.5, label_y, text="L", fill=label_color, font=label_font, anchor="center")
        canvas.create_text((right_zero_x + width) * 0.5, label_y, text="R", fill=label_color, font=label_font, anchor="center")

        pad_y = max(5, int(round(height * 0.04)))
        usable_h = max(1, height - pad_y * 2)
        gap = max(1, int(round(height / 160.0)))
        bar_h = max(2, int((usable_h - gap * (self.haptic_visual_bin_count - 1)) / self.haptic_visual_bin_count))
        max_left_w = max(1, left_zero_x - 3)
        max_right_w = max(1, (width - 4) - right_zero_x)
        center_index = (self.haptic_visual_bin_count - 1) * 0.5
        for visual_index in range(self.haptic_visual_bin_count):
            bin_index = self.haptic_visual_bin_count - 1 - visual_index
            y = pad_y + visual_index * (bar_h + gap)
            y2 = min(height - pad_y, y + bar_h)
            left_level = max(0.0, min(1.0, self.haptic_visual_left_bins[bin_index] / max(0.01, self.haptic_visual_left_peak)))
            right_level = max(0.0, min(1.0, self.haptic_visual_right_bins[bin_index] / max(0.01, self.haptic_visual_right_peak)))
            vertical_bias = (center_index - visual_index) / max(1.0, center_index)
            left_fill = self.hue_shift_hex(left_color, 0.105 * vertical_bias)
            right_fill = self.hue_shift_hex(right_color, -0.080 * vertical_bias)
            if left_level > 0.01:
                lx0 = max(2, left_zero_x - max_left_w * left_level)
                canvas.create_rectangle(lx0, y, left_zero_x - 1, y2, fill=left_fill, outline="")
            if right_level > 0.01:
                rx1 = min(width - 3, right_zero_x + max_right_w * right_level)
                canvas.create_rectangle(right_zero_x + 1, y, rx1, y2, fill=right_fill, outline="")

    def schedule_haptic_visual_decay_draw(self) -> None:
        if self.haptic_visual_decay_after_id is not None:
            return

        def tick(remaining: int = 12) -> None:
            self.haptic_visual_decay_after_id = None
            if not self.hud_window_exists(self.haptic_visual_hud_window):
                return
            self.draw_haptic_visual_hud()
            if remaining <= 0:
                return
            if max(self.haptic_visual_left_bins + self.haptic_visual_right_bins, default=0.0) <= 0.01:
                return
            try:
                self.haptic_visual_decay_after_id = self.root.after(70, lambda: tick(remaining - 1))
            except tk.TclError:
                self.haptic_visual_decay_after_id = None

        try:
            self.haptic_visual_decay_after_id = self.root.after(70, tick)
        except tk.TclError:
            self.haptic_visual_decay_after_id = None

