    def update_check_text(self, key: str, language: str | None = None, **kwargs) -> str:
        code = self.normalized_language_code_for_target("tooltip", language or self.current_tooltip_language_code())
        text = UPDATE_CHECK_TEXTS.get(code, UPDATE_CHECK_TEXTS["EN"]).get(
            key,
            UPDATE_CHECK_TEXTS["EN"].get(key, key),
        )
        return text.format(**kwargs) if kwargs else text

    def set_update_check_busy(self, busy: bool, language: str | None = None) -> None:
        button = getattr(self, "update_check_button", None)
        if button is None:
            return
        button.label_button_disabled = busy
        try:
            if busy:
                button.configure(text=self.update_check_text("checking", language), bg="#1d232a", fg="#9aa6b2")
            else:
                button.configure(
                    text=self.ui_text("Check for Updates"),
                    bg=button.default_bg,
                    fg=button.default_fg,
                )
        except tk.TclError:
            pass

    def check_for_updates(self) -> None:
        if getattr(self, "update_check_in_progress", False):
            return
        language = self.current_tooltip_language_code()
        self.update_check_in_progress = True
        self.set_update_check_busy(True, language)
        self.value_text.set(self.update_check_text("checking", language))
        thread = threading.Thread(target=self.check_for_updates_worker, args=(language,), daemon=True)
        thread.start()

    def check_for_updates_worker(self, language: str) -> None:
        latest_version = ""
        error = ""
        not_found = False
        try:
            request = urllib.request.Request(
                GITHUB_LATEST_RELEASE_API_URL,
                headers={
                    "Accept": "application/vnd.github+json",
                    "User-Agent": f"DualSense-Haptic-Translator/{APP_RELEASE_VERSION}",
                },
            )
            with urllib.request.urlopen(request, timeout=8) as response:
                data = json.loads(response.read().decode("utf-8"))
            latest_version = str(data.get("tag_name") or data.get("name") or "").strip()
            if not latest_version:
                raise RuntimeError("latest release tag was empty")
        except urllib.error.HTTPError as exc:
            if exc.code == 404:
                not_found = True
            else:
                error = f"HTTP Error {exc.code}: {exc.reason}"
        except (OSError, urllib.error.URLError, json.JSONDecodeError, RuntimeError) as exc:
            error = str(exc)
        try:
            self.root.after(0, lambda: self.finish_update_check(latest_version, error, language, not_found))
        except tk.TclError:
            pass

    def finish_update_check(self, latest_version: str, error: str, language: str, not_found: bool = False) -> None:
        self.update_check_in_progress = False
        self.set_update_check_busy(False, language)
        parent = self.root
        try:
            if self.options_window is not None and self.options_window.winfo_exists():
                parent = self.options_window
        except tk.TclError:
            parent = self.root
        current_version = APP_RELEASE_VERSION
        if not_found:
            self.value_text.set(self.update_check_text("not_found_status", language))
            open_project = messagebox.askyesno(
                self.update_check_text("not_found_title", language),
                self.update_check_text("not_found_message", language),
                parent=parent,
            )
            if open_project:
                self.open_github_project()
            return

        if error:
            self.value_text.set(self.update_check_text("failed", language, error=error))
            messagebox.showwarning(
                self.update_check_text("error_title", language),
                self.update_check_text("error_message", language, error=error),
                parent=parent,
            )
            return

        if compare_versions(latest_version, current_version) > 0:
            self.value_text.set(self.update_check_text("done_update", language, latest=latest_version))
            open_project = messagebox.askyesno(
                self.update_check_text("update_title", language),
                self.update_check_text(
                    "update_message",
                    language,
                    current=current_version,
                    latest=latest_version,
                ),
                parent=parent,
            )
            if open_project:
                self.open_github_project()
                self.value_text.set(self.update_check_text("opened", language))
            return

        self.value_text.set(self.update_check_text("done_latest", language, latest=latest_version))
        messagebox.showinfo(
            self.update_check_text("latest_title", language),
            self.update_check_text("latest_message", language, current=current_version),
            parent=parent,
        )

