    def popup_position_near_root(
        self,
        width: int,
        height: int,
        preferred_x: int | None = None,
        preferred_y: int | None = None,
        anchor: str = "pointer",
    ) -> tuple[int, int]:
        self.root.update_idletasks()
        root_x = self.root.winfo_rootx()
        root_y = self.root.winfo_rooty()
        root_w = max(1, self.root.winfo_width())
        root_h = max(1, self.root.winfo_height())
        if anchor == "center":
            x = root_x + (root_w - width) // 2
            y = root_y + (root_h - height) // 2
        else:
            x = preferred_x if preferred_x is not None else root_x + 24
            y = preferred_y if preferred_y is not None else root_y + 24
        min_x = root_x + 8
        min_y = root_y + 8
        max_x = root_x + max(8, root_w - width - 8)
        max_y = root_y + max(8, root_h - height - 8)
        return max(min_x, min(x, max_x)), max(min_y, min(y, max_y))

    def select_options_section(self, section: str) -> None:
        if section not in {"backup", "language", "hud_units", "telemetry_relay", "dsx_udp", "preset_shortcut"}:
            section = "backup"
        self.close_language_popup()
        self.options_section.set(section)
        for key, button in getattr(self, "options_nav_buttons", {}).items():
            selected = key == section
            next_bg = "#1f6feb" if selected else "#1b2027"
            next_fg = "#ffffff" if selected else "#d6dde5"
            button.default_bg = next_bg
            button.default_fg = next_fg
            button.hover_bg = "#2f81f7" if selected else "#252c35"
            button.hover_fg = "#ffffff" if selected else "#f1c40f"
            button.configure(
                bg=next_bg,
                fg=next_fg,
            )
        self.render_options_section(section)

    def render_options_section(self, section: str) -> None:
        detail = getattr(self, "options_detail_frame", None)
        if detail is None:
            return
        for child in detail.winfo_children():
            child.destroy()
        if section == "backup":
            self.render_backup_options(detail)
        elif section == "language":
            self.render_language_options(detail)
        elif section == "hud_units":
            self.render_hud_unit_options(detail)
        elif section == "telemetry_relay":
            self.render_telemetry_relay_options(detail)
        elif section == "dsx_udp":
            self.render_dsx_udp_options(detail)
        elif section == "preset_shortcut":
            self.render_preset_shortcut_options(detail)
        self.suppress_keyboard_focus_flash_tree(detail)

