    def render_hud_unit_choice(
        self,
        parent: tk.Frame,
        row: int,
        title: str,
        description: str,
        variable: tk.StringVar,
        choices: tuple[tuple[str, str], ...],
        command,
    ) -> None:
        frame = tk.Frame(parent, bg="#171b20")
