        selected_trigger = str(self.settings.get("selected_trigger_effect", self.selected_trigger_effect.get()))
        if selected_trigger not in DEFAULT_TRIGGER_SETTINGS and selected_trigger != TRIGGER_DRIFT_RUMBLE_FADE:
            selected_trigger = TRIGGER_BRAKE_RESISTANCE
        if selected_trigger == TRIGGER_MODE_TEST and not DEV_TRIGGER_MODE_TEST_ENABLED:
            selected_trigger = TRIGGER_BRAKE_RESISTANCE_PREDICTIVE
