    def init_trigger_mode_effect_vars(self, trigger_test_settings: dict) -> None:
        effects = trigger_test_settings.get("effects")
        if not isinstance(effects, dict):
            effects = {}

        def effect_state(
            key: str,
            defaults: dict[str, int],
            ranges: dict[str, tuple[int, int]] | None = None,
        ) -> None:
            current = effects.get(key)
            if not isinstance(current, dict):
                current = {}
            state: dict[str, tk.IntVar | tk.StringVar] = {}
            for name, default in defaults.items():
                minimum, maximum = (ranges or {}).get(name, (0, 9))
                value = self.clamp_int(current.get(name, default), minimum, maximum)
                state[name] = tk.IntVar(value=value)
                state[f"{name}_text"] = tk.StringVar(value=str(value))
            self.trigger_mode_effect_vars[key] = state

        effect_state("wall", {"start": 5, "strength": 2})
        effect_state("trigger_gun", {"start": 4, "end": 7, "strength": 4})
        effect_state("trigger_gun_release", {"start": 4, "end": 7, "strength": 4})
        effect_state(
            "soft_vibration",
            {"start": 1, "amp": 1, "hz": 40},
            {"start": (0, 9), "amp": (1, 8), "hz": (1, 180)},
        )
        effect_state(
            "soft_multi_zone",
            {
                "hz": 37,
                "zone_1": 4,
                "zone_2": 4,
                "zone_3": 4,
                "zone_4": 4,
                "zone_5": 0,
                "zone_6": 0,
                "zone_7": 0,
                "zone_8": 8,
                "zone_9": 8,
                "zone_10": 8,
            },
            {
                "hz": (1, 180),
                "zone_1": (0, 8),
                "zone_2": (0, 8),
                "zone_3": (0, 8),
                "zone_4": (0, 8),
                "zone_5": (0, 8),
                "zone_6": (0, 8),
                "zone_7": (0, 8),
                "zone_8": (0, 8),
                "zone_9": (0, 8),
                "zone_10": (0, 8),
            },
        )
        effect_state(
            "strong_vibration",
            {"start": 1, "amp": 80, "hz": 80},
            {"start": (0, 9), "amp": (1, 255), "hz": (1, 180)},
        )

    def open_trigger_mode_test_window(self) -> None:
        if not DEV_TRIGGER_MODE_TEST_ENABLED:
            return
        if self.trigger_mode_test_window is not None and self.trigger_mode_test_window.winfo_exists():
            self.trigger_mode_test_window.lift()
            self.trigger_mode_test_window.focus_force()
            return

        window = tk.Toplevel(self.root)
        self.trigger_mode_test_window = window
        window.title("Trigger Mode Test Console")
        window.configure(bg="#121417")
        apply_windows_dark_titlebar(window)
        self.root.update_idletasks()
        root_x = self.root.winfo_rootx()
        root_y = self.root.winfo_rooty()
        root_w = max(1, self.root.winfo_width())
        root_h = max(1, self.root.winfo_height())
        root_center_x = root_x + root_w / 2.0
        root_center_y = root_y + root_h / 2.0
        work_areas = windows_monitor_work_areas()

        def area_score(area: tuple[int, int, int, int]) -> float:
            left, top, right, bottom = area
            if left <= root_center_x < right and top <= root_center_y < bottom:
                return -1.0
            area_x = (left + right) / 2.0
            area_y = (top + bottom) / 2.0
            return (area_x - root_center_x) ** 2 + (area_y - root_center_y) ** 2

        if work_areas:
            screen_left, screen_top, screen_right, screen_bottom = min(work_areas, key=area_score)
        else:
            screen_left, screen_top = 0, 0
            screen_right, screen_bottom = self.root.winfo_screenwidth(), self.root.winfo_screenheight()

        margin = ui_px(12)
        available_w = max(1, screen_right - screen_left - margin * 2)
        available_h = max(1, screen_bottom - screen_top - margin * 2)
        window_width = min(max(1, int(round(root_w * 0.80))), available_w)
        window_height = min(max(1, int(round(root_h * 0.80))), available_h)
        x = int(round(root_center_x - window_width / 2.0))
        y = int(round(root_center_y - window_height / 2.0))
        x = max(screen_left + margin, min(x, screen_right - margin - window_width))
        y = max(screen_top + margin, min(y, screen_bottom - margin - window_height))
        window.geometry(f"{window_width}x{window_height}+{x}+{y}")
        window.protocol("WM_DELETE_WINDOW", self.close_trigger_mode_test_window)

        scroll_shell = tk.Frame(window, bg="#121417")
        scroll_shell.pack(fill="both", expand=True, padx=12, pady=12)
        scroll_shell.grid_rowconfigure(0, weight=1)
        scroll_shell.grid_columnconfigure(0, weight=1)

        canvas = tk.Canvas(scroll_shell, bg="#171b20", highlightthickness=0, bd=0)
        scrollbar = tk.Scrollbar(scroll_shell, orient="vertical", command=canvas.yview)
        canvas.configure(yscrollcommand=scrollbar.set)
        canvas.grid(row=0, column=0, sticky="nsew")
        scrollbar.grid(row=0, column=1, sticky="ns")

        body = tk.Frame(canvas, bg="#171b20", padx=14, pady=14)
        body_window = canvas.create_window((0, 0), window=body, anchor="nw")

        def refresh_scroll_region(_event=None) -> None:
            canvas.configure(scrollregion=canvas.bbox("all"))

        def fit_body_width(event) -> None:
            canvas.itemconfigure(body_window, width=max(1, event.width))
            refresh_scroll_region()

        def on_mouse_wheel(event) -> str:
            delta = -1 * int(event.delta / 120) if event.delta else 0
            if delta:
                canvas.yview_scroll(delta, "units")
            return "break"

        body.bind("<Configure>", refresh_scroll_region)
        canvas.bind("<Configure>", fit_body_width)
        window.bind("<MouseWheel>", on_mouse_wheel)
        body.grid_columnconfigure(0, weight=1)
        body.grid_columnconfigure(1, weight=1)

        left_panel = tk.Frame(body, bg="#171b20")
        left_panel.grid(row=0, column=0, sticky="nsew", padx=(0, 8))
        left_panel.grid_columnconfigure(0, weight=1)

        right_panel = tk.Frame(body, bg="#171b20")
        right_panel.grid(row=0, column=1, sticky="nsew", padx=(8, 0))
        right_panel.grid_columnconfigure(0, weight=1)

        self.build_trigger_mode_effect_section(
            left_panel,
            0,
            "Wall",
            "core_wall",
            "A resistance wall begins at the start position.",
            [
                ("Start Position", "start"),
                ("Resistance Strength", "strength"),
            ],
        )
        self.build_trigger_mode_effect_section(
            left_panel,
            1,
            "Trigger Gun",
            "core_trigger_gun",
            "A wall exists from start to end, then clicks/releases at the end.",
            [
                ("Start Position", "start"),
                ("End Position", "end"),
                ("Resistance Strength", "strength"),
            ],
        )
        self.build_trigger_mode_effect_section(
            left_panel,
            2,
            "Trigger Gun 2 (no gun pressure)",
            "core_trigger_gun_release",
            "A wall exists from start to end, then drops to Off when the physical trigger reaches the end.",
            [
                ("Start Position", "start"),
                ("End Position", "end"),
                ("Resistance Strength", "strength"),
            ],
        )
        self.build_trigger_mode_effect_section(
            left_panel,
            3,
            "Soft Pulse Vibration",
            "core_soft_vibration",
            "A no-wall zone vibration starts after the trigger reaches the selected position.",
            [
                ("Start Position", "start", 0, 9),
                ("Amp", "amp", 1, 8),
                ("Hz", "hz", 1, 180),
            ],
        )
        self.build_trigger_mode_effect_section(
            right_panel,
            0,
            "Soft Pulse Multi Zone",
            "core_soft_multi_zone",
            "One frequency drives a custom 10-zone amplitude map.",
            [
                ("Hz", "hz", 1, 180),
                ("Zone 1 Amp", "zone_1", 0, 8),
                ("Zone 2 Amp", "zone_2", 0, 8),
                ("Zone 3 Amp", "zone_3", 0, 8),
                ("Zone 4 Amp", "zone_4", 0, 8),
                ("Zone 5 Amp", "zone_5", 0, 8),
                ("Zone 6 Amp", "zone_6", 0, 8),
                ("Zone 7 Amp", "zone_7", 0, 8),
                ("Zone 8 Amp", "zone_8", 0, 8),
                ("Zone 9 Amp", "zone_9", 0, 8),
                ("Zone 10 Amp", "zone_10", 0, 8),
            ],
        )
        self.build_trigger_mode_effect_section(
            right_panel,
            1,
            "Strong Pulse Vibration",
            "core_strong_vibration",
            "A stronger firmware pulse starts at the selected trigger position.",
            [
                ("Start Position", "start", 0, 9),
                ("Amp", "amp", 1, 255),
                ("Hz", "hz", 1, 180),
            ],
        )

        grid = tk.Frame(body, bg="#171b20")
        grid.grid(row=1, column=0, columnspan=2, sticky="ew", pady=(16, 0))
        for column in range(3):
            grid.grid_columnconfigure(column, weight=1)

        for index, (label, preset) in enumerate(self.trigger_mode_test_presets()):
            preset_button = self.create_popup_label_button(
                grid,
                text=label,
                command=lambda value=preset: self.send_trigger_mode_test(value),
                bg="#252c35",
                fg="#d6dde5",
                bd=0,
                padx=8,
                pady=5,
                font=ui_font("Segoe UI", 9, "bold"),
                hover_bg="#f1c40f",
                hover_fg="#101316",
            )
            preset_button.grid(row=index // 3, column=index % 3, sticky="ew", padx=4, pady=4)

        tk.Label(
            body,
            textvariable=self.trigger_mode_test_status,
            bg="#171b20",
            fg="#f1c40f",
            font=ui_font("Segoe UI", 10, "bold"),
            anchor="w",
        ).grid(row=2, column=0, columnspan=2, sticky="ew", pady=(12, 0))

