    def build_trigger_mode_effect_section(
        self,
        parent: tk.Widget,
        row: int,
        title: str,
        preset: str,
        description: str,
        fields: list[tuple[str, str]],
    ) -> None:
        key = {
            "core_wall": "wall",
            "core_trigger_gun": "trigger_gun",
            "core_trigger_gun_release": "trigger_gun_release",
            "core_soft_vibration": "soft_vibration",
            "core_soft_multi_zone": "soft_multi_zone",
            "core_strong_vibration": "strong_vibration",
        }[preset]
        state = self.trigger_mode_effect_vars[key]
        frame = tk.Frame(parent, bg="#12161b", padx=12, pady=10, highlightthickness=1, highlightbackground="#2e3742")
        frame.grid(row=row, column=0, sticky="ew", pady=(0, 10))
        frame.grid_columnconfigure(0, weight=1)

        header = tk.Frame(frame, bg="#12161b")
        header.grid(row=0, column=0, sticky="ew")
        header.grid_columnconfigure(0, weight=1)
        tk.Label(
            header,
            text=f"Effect: {title}",
            bg="#12161b",
            fg="#f1c40f",
            font=ui_font("Segoe UI", 11, "bold"),
            anchor="w",
        ).grid(row=0, column=0, sticky="w")
        self.create_popup_label_button(
            header,
            text="TEST",
            command=lambda value=preset: self.send_trigger_mode_effect_test(value),
            bg="#252c35",
            fg="#d6dde5",
            bd=0,
            padx=12,
            pady=5,
            font=ui_font("Segoe UI", 9, "bold"),
            hover_bg="#f1c40f",
            hover_fg="#101316",
        ).grid(row=0, column=1, sticky="e")

        tk.Label(
            frame,
            text=description,
            bg="#12161b",
            fg="#aeb8c4",
            font=ui_font("Segoe UI", 9),
            anchor="w",
        ).grid(row=1, column=0, sticky="ew", pady=(2, 8))

        for field_row, field in enumerate(fields, start=2):
            label, field_key = field[0], field[1]
            minimum = field[2] if len(field) >= 3 else 0
            maximum = field[3] if len(field) >= 4 else 9
            var = state[field_key]
            text_var = state[f"{field_key}_text"]
            assert isinstance(var, tk.IntVar)
            assert isinstance(text_var, tk.StringVar)
            self.build_trigger_mode_test_int_control(
                field_row,
                label,
                var,
                text_var,
                minimum,
                maximum,
                parent=frame,
            )

