    def road_bumps_threshold_scale(self) -> float:
        sensitivity = self.road_bumps_detail_value("bump_sensitivity")
        return max(0.55, min(1.45, 1.0 - (sensitivity - 5.0) * 0.09))

    def road_bumps_low_class_correction_scale(self) -> float:
        correction = self.road_bumps_detail_value("low_class_correction")
        return max(0.0, min(10.0 / 3.0, correction / 3.0))

    def road_bumps_strength_gain(self, target_level: float) -> float:
        small_gain = self.road_bumps_detail_value("small_bump_strength") / 5.0
        large_gain = self.road_bumps_detail_value("large_bump_strength") / 5.0
        large_mix = self.smoothstep(0.35, 0.75, target_level)
        return small_gain * (1.0 - large_mix) + large_gain * large_mix

    def road_bumps_attack_alpha(self) -> float:
        attack = self.road_bumps_detail_value("attack")
        if attack <= 5:
            return 0.42 + (0.82 - 0.42) * (attack / 5.0)
        return 0.82 + (0.95 - 0.82) * ((attack - 5.0) / 5.0)

    def road_bumps_decay_scale(self) -> float:
        decay = self.road_bumps_detail_value("decay")
        return 0.60 + decay * 0.08

